//-----------------------------------------------------------------------------
// MRFPointVentDlg : GetProfileValues
// Get 3D Profile values
//-----------------------------------------------------------------------------
void MRFPointVentDlg::GetProfileValues(int iProfileIndex, CATListOfDouble & oListValues)
{
	oListValues.RemoveAll();

	if (0 == iProfileIndex)
	{
		double a = GetDoubleValueFromSpinner(_pProfile1A);
		oListValues.Append(a);

		double b = GetDoubleValueFromSpinner(_pProfile1B);
		oListValues.Append(b);

		double c = GetDoubleValueFromSpinner(_pProfile1C);
		oListValues.Append(c);

		double d = GetDoubleValueFromSpinner(_pProfile1D);
		oListValues.Append(d);
	}
	else  if (1 == iProfileIndex)
	{
		double a = GetDoubleValueFromSpinner(_pProfile2A);
		oListValues.Append(a);

		double b = GetDoubleValueFromSpinner(_pProfile2B);
		oListValues.Append(b);
	}

}

//-----------------------------------------------------------------------------
// MRFPointVentDlg : GetDoubleValueFromSpinner
// Get double value
//-----------------------------------------------------------------------------
double MRFPointVentDlg::GetDoubleValueFromSpinner(CATDlgSpinner* ipSpinner)
{
	double value = 0.;
	
	if (NULL != ipSpinner)
	{
		float fvalue = ipSpinner->GetCurrentValue();
		value = (double) fvalue;
	}

	return value;
}

//-----------------------------------------------------------------------------
// MRFPointVentDlg : SetDoubleValueFromSpinner
// Set double value
//-----------------------------------------------------------------------------
void MRFPointVentDlg::SetDoubleValueFromSpinner(CATDlgSpinner* ipSpinner, double iValue)
{
	if (NULL != ipSpinner)
	{
		float fValue = (float)iValue;
		ipSpinner->SetCurrentValue(fValue);
	}
}

//-----------------------------------------------------------------------------
// MRFPointVentDlg : SetProfileValues
// Set 3D Profile values
//-----------------------------------------------------------------------------
void MRFPointVentDlg::SetProfileValues(int iProfileIndex, CATListOfDouble iListValues)
{
	if (iListValues.Size() > 0)
	{
		if (0 == iProfileIndex)
		{
			SetDoubleValueFromSpinner(_pProfile1A, iListValues[1]);
			SetDoubleValueFromSpinner(_pProfile1B, iListValues[2]);
			SetDoubleValueFromSpinner(_pProfile1C, iListValues[3]);
			SetDoubleValueFromSpinner(_pProfile1D, iListValues[4]);
		}
		else  if (1 == iProfileIndex)
		{
			SetDoubleValueFromSpinner(_pProfile2A, iListValues[1]);
			SetDoubleValueFromSpinner(_pProfile2B, iListValues[2]);
		}
	}
}

void MRFPointVentDlg::SetPreviewON(int iTypeIndex, CATBoolean iVisibility)
{
	CATDlgPushButton* pPreviewButton = NULL;

	if (0 == iTypeIndex)
	{
		pPreviewButton = _pSingleEdgePreview;
	}
	else  if (1 == iTypeIndex)
	{
		pPreviewButton = _pDualEdgeFirstEdgePreview;
	}
	else if (2 == iTypeIndex)
	{
		pPreviewButton = _pCurveEdgePreview;
	}
	else  if (3 == iTypeIndex)
	{
		pPreviewButton = _pEdgeVentPreview;
	}

	if (NULL != pPreviewButton)
	{
		if (iVisibility)
		{
			pPreviewButton->SetIconName("I_MRFViewON");
		}
		else if (!iVisibility)
		{
			pPreviewButton->SetIconName("I_MRFView");
		}
	}
}

void MRFPointVentDlg::SetSecondPreviewON(int iTypeIndex, CATBoolean iVisibility)
{
	CATDlgPushButton* pPreviewButton = NULL;

	if (1 == iTypeIndex)
	{
		pPreviewButton = _pDualEdgeSecondEdgePreview;
	}

	if (NULL != pPreviewButton)
	{
		if (iVisibility)
		{
			pPreviewButton->SetIconName("I_MRFViewON");
		}
		else if (!iVisibility)
		{
			pPreviewButton->SetIconName("I_MRFView");
		}
	}
}
void MRFPointVentDlg::GetSegmentVentUVValues(double & oU, double & oV)
{
	float U = 0.f;
	float V = 0.f;
	U = _pRefVentU->GetFloatValue();
	V = _pRefVentV->GetFloatValue();

	oU = (double)U;
	oV = (double)V;
}
void MRFPointVentDlg::UpdateSegmentVentUVValues(double iU, double iV)
{
	float U = (float)iU;
	float V = (float)iV;
	_pRefVentU->SetFloatValue(U);
	_pRefVentV->SetFloatValue(V);
}

void MRFPointVentDlg::UpdateSegmentVentDeltaUVValues(double iDeltaU, double iDeltaV)
{
	float DeltaU = (float)iDeltaU;
	float DeltaV = (float)iDeltaV;
	
	_pRefVentDeltaU->SetCurrentValue(DeltaU);
	_pRefVentDeltaV->SetCurrentValue(DeltaV);

}

void MRFPointVentDlg::GetSegmentVentDeltaUVValues(double & oDeltaU, double & oDeltaV)
{
	float U = 0.f;
	float V = 0.f;
	U = _pRefVentDeltaU->GetCurrentValue();
	V = _pRefVentDeltaV->GetCurrentValue();

	oDeltaU = (double)U;
	oDeltaV = (double)V;
}




